('business:3-5-motivation-and-retention:match:27d80f8d', 'business', 'business:3-5-motivation-and-retention', '3.5 Motivation and Retention', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Motivation”?", "options": ["The quality of the physical workplace and its social climate, including how workers are treated and whether they feel respected.", "An additional payment to workers for achieving a measurable target, such as reaching a sales goal or production level.", "A measure of output per worker — one way of measuring the performance of employees.", "The encouragement given to workers to work well, making them feel responsible, fulfilled and happy."]}'::jsonb, '{"answer": 3, "explain": "“Motivation” means: The encouragement given to workers to work well, making them feel responsible, fulfilled and happy."}'::jsonb),
('business:3-5-motivation-and-retention:match:6c74e627', 'business', 'business:3-5-motivation-and-retention', '3.5 Motivation and Retention', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Retention”?", "options": ["A non-financial method of motivating workers by complimenting their work and making their effort feel recognised.", "The quality of the physical workplace and its social climate, including how workers are treated and whether they feel respected.", "A measure of the number or proportion of staff who leave an organisation each year and who need to be replaced.", "When workers choose to stay employed in a business rather than leaving to work elsewhere."]}'::jsonb, '{"answer": 3, "explain": "“Retention” means: When workers choose to stay employed in a business rather than leaving to work elsewhere."}'::jsonb),
('business:3-5-motivation-and-retention:match:0903e76a', 'business', 'business:3-5-motivation-and-retention', '3.5 Motivation and Retention', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Labour Turnover”?", "options": ["A system where workers receive extra pay based on how well they perform against a measurable target.", "A measure of the number or proportion of staff who leave an organisation each year and who need to be replaced.", "A tangible form of recognition — such as a certificate, badge, or voucher — presented to acknowledge a worker''s effort.", "A weekly system of pay calculated by multiplying hours worked by the hourly rate."]}'::jsonb, '{"answer": 1, "explain": "“Labour Turnover” means: A measure of the number or proportion of staff who leave an organisation each year and who need to be replaced."}'::jsonb),
