('business:3-5-motivation-and-retention:match:d9a6a663', 'business', 'business:3-5-motivation-and-retention', '3.5 Motivation and Retention', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Working Environment”?", "options": ["The quality of the physical workplace and its social climate, including how workers are treated and whether they feel respected.", "When workers receive a set proportion of the profits made by a business.", "A system where workers receive extra pay based on how well they perform against a measurable target.", "When workers take time off work without good reason. High absenteeism is a sign of poor motivation and increases business costs."]}'::jsonb, '{"answer": 0, "explain": "“Working Environment” means: The quality of the physical workplace and its social climate, including how workers are treated and whether they feel respected."}'::jsonb),
